mapper.select:
SELECT * FROM standard_parameters

    AND standard_document_id = #{standardDocumentId}
    AND parameter_standard_id = #{parameterStandardId}
    AND active = #{active}
    AND (code LIKE CONCAT('%',#{keyword},'%') OR name LIKE CONCAT('%',#{keyword},'%') OR value LIKE CONCAT('%',#{keyword},'%') OR description LIKE CONCAT('%',#{keyword},'%'))
    AND category = #{category}

ORDER BY category ASC, code ASC
